-- 0006_seed_demo_sessions.sql — materialized past sessions (GATED).
-- Generated from apps/web/src/data/{sessions,sessionDetail}.ts by scratchpad/gen-sessions.js.
-- Per demo patient, materializes their past therapy sessions (31 total) as calendar_events
-- plus a ready meeting_summaries row (text + insight) and a transcripts row (diarized
-- segments), byte-identical to the SPA mock. All inserts are gated by app.seed_demo, so
-- production inserts 0 rows. Idempotent via ON CONFLICT. Times are Israel wall-clock.

INSERT INTO calendar_events (id, title, description, start_at, end_at, therapist_id, patient_id)
SELECT
    v.id::uuid,
    'פגישה שבועית',
    NULL,
    (v.at::timestamp AT TIME ZONE 'Asia/Jerusalem'),
    (v.at::timestamp AT TIME ZONE 'Asia/Jerusalem') + (v.dur_min || ' minutes')::interval,
    '00000000-0000-4000-8000-000000000001'::uuid,
    v.patient_id::uuid
