INSERT INTO meeting_summaries (meeting_id, status, text, model, insight)
SELECT v.meeting_id::uuid, 'ready', v.text, 'demo', v.insight
FROM (VALUES
  ('76960d3d-80ba-4c5f-ad3b-fdf104d3031e', 'המטופל דיווח על שיפור מתון בתחושת השליטה במצבי לחץ. תרגלנו נשימה סרעפתית והרחבנו את חשיפה ההדרגתית.', 'נצפה שימוש עצמאי בכלי ויסות תחת לחץ. כדאי לחזק את חוויית המסוגלות ולקשר אותה לאירועים עתידיים.'),
  ('effc7e0c-cb4e-4c2f-8dd0-ce9dca5772f4', 'עלו תכנים סביב חרדת ביצוע בעבודה. זוהו דפוסי הימנעות חוזרים; הוגדרה משימה התנהגותית לשבוע הקרוב.', 'חרדת הביצוע עדיין מניעה הימנעות, אך יש סימני התמודדות מוצלחת. המשך חשיפה הדרגתית מומלץ.'),
  ('e55660fc-898d-4909-83aa-4372a8b05094', 'הפגישה התמקדה ביחסים בין-אישיים ובקושי להציב גבולות. נצפתה עלייה ברגישות רגשית בהשוואה לפגישות קודמות.', 'עלו קשיים ביחסים בין-אישיים וגבולות. רגישות רגשית גבוהה מהממוצע בפגישות קודמות.'),
  ('e8870855-3925-4aa8-9519-2809b7204e31', 'דיווח על מצב רוח ירוד יחסית. בחנו טריגרים אפשריים ועיבדנו אירוע משמעותי מהשבוע.', 'מצב רוח ירוד יחסית. כדאי לבחון טריגרים מהשבוע האחרון.'),
  ('13794a59-1608-45cb-a79a-373d3ef60841', 'התקדמות יפה במטרות הטיפול. המטופל מתאר שימוש עצמאי בכלים שנלמדו.', 'התקדמות יציבה במטרות הטיפול. המטופל/ת מדווח/ת על שימוש עצמאי בכלים.'),
  ('110c6a2d-0b5e-44b2-84e6-7d1a714c2b12', 'עבודה על דפוסי התקשרות וקשר למשפחת המוצא. עלו זיכרונות טעונים שדרשו ויסות במהלך הפגישה.', 'דפוסי התקשרות ממשפחת המוצא עדיין משפיעים. נדרש ויסות במהלך העיבוד.'),
  ('3874081f-fcf3-4706-88ab-e486253c3549', 'חיזוק מוטיבציה והגדרה מחדש של מטרות הטיפול לרבעון הקרוב.', 'מוטיבציה גבוהה לשינוי. זמן טוב להגדרת מטרות לרבעון הקרוב.'),
