INSERT INTO transcripts (meeting_id, raw_text, diarized_segments, language)
SELECT v.meeting_id::uuid, v.raw_text, v.segments::jsonb, 'he'
FROM (VALUES
  ('76960d3d-80ba-4c5f-ad3b-fdf104d3031e', E'מטפל/ת: אז ספרי לי איך עבר עליך השבוע מאז שנפגשנו.\nמטופל/ת: הייתה לי הצגה גדולה בעבודה וכמה ימים לפני זה כמעט לא הצלחתי לישון.\nמטופל/ת: ניסיתי בבוקר ההצגה את הנשימה שתרגלנו וזה דווקא עזר. הרגשתי גאווה אחרי.', '[{"speaker":"מטפל/ת","start_time":0,"end_time":0,"text":"אז ספרי לי איך עבר עליך השבוע מאז שנפגשנו."},{"speaker":"מטופל/ת","start_time":0,"end_time":0,"text":"הייתה לי הצגה גדולה בעבודה וכמה ימים לפני זה כמעט לא הצלחתי לישון."},{"speaker":"מטופל/ת","start_time":0,"end_time":0,"text":"ניסיתי בבוקר ההצגה את הנשימה שתרגלנו וזה דווקא עזר. הרגשתי גאווה אחרי."}]'),
