  ('f5a3ee7c-7a55-48c6-960c-adbe2b44e0d5', E'מטופל/ת: השבוע היה קשה. הרגשתי ריקנות אחרי הפרידה מהחברה.\nמטפל/ת: מתי התחיל להיות שונה?', '[{"speaker":"מטופל/ת","start_time":0,"end_time":0,"text":"השבוע היה קשה. הרגשתי ריקנות אחרי הפרידה מהחברה."},{"speaker":"מטפל/ת","start_time":0,"end_time":0,"text":"מתי התחיל להיות שונה?"}]'),
  ('cf79c73f-bee8-472d-8cf8-da7410973bcc', E'מטופל/ת: השתמשתי ביומן הרגשות בכל יום השבוע.\nמטפל/ת: זו התקדמות משמעותית. מה למדת על עצמך?', '[{"speaker":"מטופל/ת","start_time":0,"end_time":0,"text":"השתמשתי ביומן הרגשות בכל יום השבוע."},{"speaker":"מטפל/ת","start_time":0,"end_time":0,"text":"זו התקדמות משמעותית. מה למדת על עצמך?"}]'),
  ('e09b4e8c-6cb5-4428-9a25-39b060781797', E'מטופל/ת: אבא שלי תמיד אמר שצריך להיות חזק. זה עדיין מלווה אותי.\nמטפל/ת: איך זה משפיע על הדרך שאת מבקשת עזרה?', '[{"speaker":"מטופל/ת","start_time":0,"end_time":0,"text":"אבא שלי תמיד אמר שצריך להיות חזק. זה עדיין מלווה אותי."},{"speaker":"מטפל/ת","start_time":0,"end_time":0,"text":"איך זה משפיע על הדרך שאת מבקשת עזרה?"}]'),
